import "reflect-metadata";
import { promises as fs } from "fs";
import path from "path";
import { DataSource } from "typeorm";
import { JobEntitySchema } from "./entities/JobEntity.js";
import { ModelTierAssignmentEntitySchema } from "./entities/ModelTierAssignmentEntity.js";
import { ObservabilityRequestEntitySchema } from "./entities/ObservabilityRequestEntity.js";
import { StepLifecycleEventEntitySchema } from "./entities/StepLifecycleEventEntity.js";
import { StepWorkItemEntitySchema } from "./entities/StepWorkItemEntity.js";
import { TickerWorkItemEntitySchema } from "./entities/TickerWorkItemEntity.js";
import { TrackedAssetEntitySchema } from "./entities/TrackedAssetEntity.js";
import { UserPointsBudgetEntitySchema } from "./entities/UserPointsBudgetEntity.js";
import { UserEntitySchema } from "./entities/UserEntity.js";
import { StrategyEntitySchema } from "./entities/StrategyEntity.js";
import { ReportBatchEntitySchema } from "./entities/ReportBatchEntity.js";
import { ReportIndexEntitySchema } from "./entities/ReportIndexEntity.js";
import { NotificationEntitySchema } from "./entities/NotificationEntity.js";
import { EscalationHistoryEntitySchema } from "./entities/EscalationHistoryEntity.js";
import { VerdictActionEntitySchema } from "./entities/VerdictActionEntity.js";
import { TickerSnoozeEntitySchema } from "./entities/TickerSnoozeEntity.js";
import { PortfolioRiskSnapshotEntitySchema } from "./entities/PortfolioRiskSnapshotEntity.js";
import { AdminAuditLogEntitySchema } from "./entities/AdminAuditLogEntity.js";
import { MigrationArchiveEntitySchema } from "./entities/MigrationArchiveEntity.js";
import { FeatureFlagEntitySchema } from "./entities/FeatureFlagEntity.js";
import { ChannelBindingEntitySchema } from "./entities/ChannelBindingEntity.js";
import { EncryptedSecretEntitySchema } from "./entities/EncryptedSecretEntity.js";
import { ConversationEntitySchema } from "./entities/ConversationEntity.js";
import { ConversationTurnEntitySchema } from "./entities/ConversationTurnEntity.js";
import { ToolCallEntitySchema } from "./entities/ToolCallEntity.js";
import { OutputFilterEventEntitySchema } from "./entities/OutputFilterEventEntity.js";
import { PositionTransactionEntitySchema } from "./entities/PositionTransactionEntity.js";
import { CorporateActionEntitySchema } from "./entities/CorporateActionEntity.js";
import { logger } from "../services/logger.js";

const APP_DATABASE_URL =
  process.env["APP_DATABASE_URL"] ??
  process.env["OBSERVABILITY_DATABASE_URL"] ??
  "";
const APP_DATABASE_DDL_PATH =
  process.env["APP_DATABASE_DDL_PATH"] ??
  process.env["OBSERVABILITY_DDL_PATH"] ??
  path.resolve(process.cwd(), "../db/application_postgres.sql");

let dataSource: DataSource | null = null;
let ddlApplied = false;

export function isApplicationDatabaseConfigured(): boolean {
  return APP_DATABASE_URL.length > 0;
}

function buildDataSource(): DataSource {
  if (!APP_DATABASE_URL) {
    throw new Error("APP_DATABASE_URL is required");
  }

  return new DataSource({
    type: "postgres",
    url: APP_DATABASE_URL,
    entities: [
      JobEntitySchema,
      ModelTierAssignmentEntitySchema,
      ObservabilityRequestEntitySchema,
      StepLifecycleEventEntitySchema,
      StepWorkItemEntitySchema,
      TickerWorkItemEntitySchema,
      TrackedAssetEntitySchema,
      UserPointsBudgetEntitySchema,
      // Phase 1 (design.md §4.1–4.17):
      UserEntitySchema,
      StrategyEntitySchema,
      ReportBatchEntitySchema,
      ReportIndexEntitySchema,
      NotificationEntitySchema,
      EscalationHistoryEntitySchema,
      VerdictActionEntitySchema,
      TickerSnoozeEntitySchema,
      PortfolioRiskSnapshotEntitySchema,
      AdminAuditLogEntitySchema,
      MigrationArchiveEntitySchema,
      FeatureFlagEntitySchema,
      ChannelBindingEntitySchema,
      EncryptedSecretEntitySchema,
      // Phase 5 (design.md §4.11–4.12):
      ConversationEntitySchema,
      ConversationTurnEntitySchema,
      ToolCallEntitySchema,
      OutputFilterEventEntitySchema,
      // Phase 7 (design.md §4.6–4.7):
      PositionTransactionEntitySchema,
      CorporateActionEntitySchema,
    ],
    synchronize: false,
    logging: false,
  });
}

async function applyDdl(ds: DataSource): Promise<void> {
  if (ddlApplied) return;
  const ddl = await fs.readFile(APP_DATABASE_DDL_PATH, "utf-8");
  await ds.query(ddl);
  ddlApplied = true;
}

export async function getApplicationDataSource(): Promise<DataSource> {
  if (!dataSource) {
    dataSource = buildDataSource();
  }

  if (!dataSource.isInitialized) {
    await dataSource.initialize();
    await applyDdl(dataSource);
    logger.info("Application PostgreSQL data source initialized");
  }

  return dataSource;
}

export async function closeApplicationDataSource(): Promise<void> {
  if (dataSource?.isInitialized) {
    await dataSource.destroy();
  }
  dataSource = null;
  ddlApplied = false;
}

import { z } from "zod";

export const PilotFeatureSurfaceSchema = z.enum(["admin", "operator", "telegram", "web"]);

export const PilotFeatureReviewStatusSchema = z.enum([
  "unreviewed",
  "needs_fix",
  "beta",
  "hidden",
  "ready",
]);

export const PilotFeatureRecommendationSchema = z.enum([
  "pilot",
  "beta",
  "defer",
  "hide",
]);

const NonEmptyStringArraySchema = z.array(z.string().trim().min(1)).min(1);

export const PilotFeatureCatalogEntrySchema = z.object({
  id: z.string().trim().min(1).regex(/^[a-z0-9]+(?:[._-][a-z0-9]+)*$/),
  surface: PilotFeatureSurfaceSchema,
  title: z.string().trim().min(1),
  shortSummary: z.string().trim().min(1),
  detailedExplanation: z.string().trim().min(1),
  happyPath: NonEmptyStringArraySchema,
  edgeCases: NonEmptyStringArraySchema,
  errorHandling: NonEmptyStringArraySchema,
  evidencePaths: NonEmptyStringArraySchema,
  pilotRecommendation: PilotFeatureRecommendationSchema,
}).strict();

export const PilotFeatureCatalogFileSchema = z.object({
  entries: z.array(PilotFeatureCatalogEntrySchema).min(1),
}).strict();

export type PilotFeatureSurface = z.infer<typeof PilotFeatureSurfaceSchema>;
export type PilotFeatureReviewStatus = z.infer<typeof PilotFeatureReviewStatusSchema>;
export type PilotFeatureRecommendation = z.infer<typeof PilotFeatureRecommendationSchema>;
export type PilotFeatureCatalogEntry = z.infer<typeof PilotFeatureCatalogEntrySchema>;
export type PilotFeatureCatalogFile = z.infer<typeof PilotFeatureCatalogFileSchema>;

import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { ZodError } from "zod";
import {
  PilotFeatureCatalogFileSchema,
  type PilotFeatureCatalogEntry,
} from "../schemas/pilotFeature.js";

const SERVICES_DIR = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(SERVICES_DIR, "..", "..", "..");
const DEFAULT_CATALOG_DIR = path.join(PROJECT_ROOT, "docs", "pilot-features");

const UNSAFE_EVIDENCE_PATTERNS = [
  /^users(?:\/|$)/,
  /^\.env$/,
  /(?:^|\/)\.env(?:\.|$)/,
  /^backend\/\.env$/,
  /^data\/(?:tickers|reports|jobs|triggers|state|research)(?:\/|$)/,
  /^backend\/(?:dist|logs|node_modules)(?:\/|$)/,
  /^\.gsd(?:\/|$)/,
  /^\.openclaw(?:\/|$)/,
  /^memory(?:\/|$)/,
  /^canvas(?:\/|$)/,
];

export class PilotFeatureCatalogError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PilotFeatureCatalogError";
  }
}

export interface LoadPilotFeatureCatalogOptions {
  catalogDir?: string;
}

function formatZodIssuePath(pathSegments: Array<string | number>): string {
  return pathSegments.length > 0 ? pathSegments.join(".") : "<root>";
}

function formatZodError(error: ZodError): string {
  return error.issues
    .map((issue) => `${formatZodIssuePath(issue.path)}: ${issue.message}`)
    .join("; ");
}

function normalizeEvidencePath(evidencePath: string): string {
  return evidencePath.trim().replace(/\\/g, "/").replace(/^\.\//, "");
}

function assertSafeEvidencePath(entry: PilotFeatureCatalogEntry, evidencePath: string, filePath: string): void {
  const normalized = normalizeEvidencePath(evidencePath);
  if (path.isAbsolute(evidencePath) || normalized.includes("../")) {
    throw new PilotFeatureCatalogError(
      `${filePath}: Unsafe evidence path for ${entry.id}: ${evidencePath}`
    );
  }
  if (UNSAFE_EVIDENCE_PATTERNS.some((pattern) => pattern.test(normalized))) {
    throw new PilotFeatureCatalogError(
      `${filePath}: Unsafe evidence path for ${entry.id}: ${evidencePath}`
    );
  }
}

async function parseCatalogFile(filePath: string): Promise<PilotFeatureCatalogEntry[]> {
  let parsed: unknown;
  try {
    parsed = JSON.parse(await fs.readFile(filePath, "utf-8"));
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    throw new PilotFeatureCatalogError(`${filePath}: Malformed JSON: ${reason}`);
  }

  const result = PilotFeatureCatalogFileSchema.safeParse(parsed);
  if (!result.success) {
    throw new PilotFeatureCatalogError(`${filePath}: ${formatZodError(result.error)}`);
  }

  for (const entry of result.data.entries) {
    for (const evidencePath of entry.evidencePaths) {
      assertSafeEvidencePath(entry, evidencePath, filePath);
    }
  }

  return result.data.entries;
}

export async function loadPilotFeatureCatalog(
  options: LoadPilotFeatureCatalogOptions = {}
): Promise<PilotFeatureCatalogEntry[]> {
  const catalogDir = options.catalogDir ?? DEFAULT_CATALOG_DIR;
  let dirents;
  try {
    dirents = await fs.readdir(catalogDir, { withFileTypes: true });
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    throw new PilotFeatureCatalogError(`${catalogDir}: Unable to read pilot feature catalog: ${reason}`);
  }

  const files = dirents
    .filter((dirent) => dirent.isFile() && dirent.name.endsWith(".json"))
    .map((dirent) => path.join(catalogDir, dirent.name))
    .sort((a, b) => a.localeCompare(b));

  const entries: PilotFeatureCatalogEntry[] = [];
  const seen = new Map<string, string>();
  for (const filePath of files) {
    const fileEntries = await parseCatalogFile(filePath);
    for (const entry of fileEntries) {
      const priorPath = seen.get(entry.id);
      if (priorPath) {
        throw new PilotFeatureCatalogError(
          `${filePath}: Duplicate pilot feature id ${entry.id}; first seen in ${priorPath}`
        );
      }
      seen.set(entry.id, filePath);
      entries.push(entry);
    }
  }

  return entries.sort((a, b) =>
    a.surface.localeCompare(b.surface) ||
    a.title.localeCompare(b.title) ||
    a.id.localeCompare(b.id)
  );
}

import { EntitySchema } from "typeorm";

export interface FeatureFlagEntity {
  id: string;
  flagName: string;
  scopeUserId: string | null;
  enabled: boolean;
  valueJson: unknown;
  updatedAt: Date;
  updatedBy: string;
}

export const FeatureFlagEntitySchema = new EntitySchema<FeatureFlagEntity>({
  name: "FeatureFlag",
  tableName: "feature_flags",
  columns: {
    id: { type: "bigint", primary: true, generated: true },
    flagName: { name: "flag_name", type: "varchar", length: 64 },
    scopeUserId: { name: "scope_user_id", type: "varchar", length: 64, nullable: true },
    enabled: { type: "boolean" },
    valueJson: { name: "value_json", type: "jsonb", nullable: true },
    updatedAt: { name: "updated_at", type: "timestamptz" },
    updatedBy: { name: "updated_by", type: "varchar", length: 64 },
  },
});

